class Home{static#build(data){const content=document.getElementById("content");data.forEach(category=>{const container=document.createElement("div");container.classList.add("category");if(category.title){const div=document.createElement("div");div.classList.add("category-title");Object.keys(category.title).forEach(local=>{const span=document.createElement("span");span.classList.add("localized");span.lang=local;span.innerHTML=category.title[local];div.appendChild(span);});container.appendChild(div);}category.projects.forEach(project=>{const card=document.createElement("div");card.classList.add("card","expanded","single");{{const div=document.createElement("div");div.classList.add("card-title","center");Object.keys(project.title).forEach(local=>{const span=document.createElement("span");span.classList.add("localized");span.lang=local;span.innerHTML=project.title[local];div.appendChild(span);});card.appendChild(div);}{const div=document.createElement("div");div.classList.add("card-description");Object.keys(project.description).forEach(local=>{const span=document.createElement("span");span.classList.add("localized");span.lang=local;span.innerHTML=project.description[local];div.appendChild(span);});card.appendChild(div);}["website","github","pdf"].forEach(key=>{if(project[key]){const div=document.createElement("div");div.classList.add("external","expanded");const span=document.createElement("span");span.classList.add("link");span.innerHTML=key;const a=document.createElement("a");a.href=project[key];a.target="_blank";a.appendChild(span);const icon=document.createElement("span");icon.classList.add("open","nowrap");{const span=document.createElement("span");span.classList.add("localized");span.lang="en";span.innerHTML="[open]";icon.appendChild(span);}{const span=document.createElement("span");span.classList.add("localized");span.lang="de";span.innerHTML="[öffnen]";icon.appendChild(span);}a.appendChild(icon);div.appendChild(a);card.appendChild(div);}});}container.appendChild(card);});content.appendChild(container);});}static build(){fetch("json/home.min.json").then(response=>response.json()).then(data=>{clear_content();Home.#build(data.content);}).then(()=>{switch_lang(window.lang);}).catch(console.error);}}